import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your_project_id',
  apiKey: process.env.VEX_API_KEY
});

// n8n webhook handler
const handler = async (req, res) => {
  const agentOutput = req.body.ai_agent_output;

  const result = await vex.check({
    inputs: {
      prompt: agentOutput.prompt,
      response: agentOutput.response,
      context: agentOutput.memory_window
    },
    rules: [
      'no-protected-class-bias',
      'explainable-insurance-decision',
      'no-credential-exposure',
      'fresh-context-validation'
    ],
    sensitivity: 'high'
  });

  if (result.valid) {
    res.json({ proceed: true, data: agentOutput });
  } else {
    res.status(403).json({ blocked: true, violations: result.violations });
  }
};

export default handler;

// In Vex dashboard or SDK rule definition
const underwritingRule = {
  name: 'insurance-underwriting-compliance',
  description: 'Blocks discriminatory or unexplained underwriting decisions',
  patterns: [
    {
      type: 'bias',
      selectors: ['race', 'gender', 'zipcode-proxy', 'ethnic-surname'],
      action: 'block'
    },
    {
      type: 'explainability',
      require: 'decision_reason_must_reference_policy_data',
      action: 'block'
    }
  ],
  metadata: {
    industry: 'insurance',
    regulation: 'NAIC Model 668'
  }
};

// Usage in n8n webhook
const result = await vex.check({
  inputs: { decision: 'Denied: High risk profile' },
  rules: [underwritingRule]
});

const toolCallValidator = async (toolParams: any) => {
  const vex = new Vex({ projectId: 'ins-project', apiKey: process.env.VEX_KEY });

  const check = await vex.check({
    inputs: {
      tool_params: JSON.stringify(toolParams),
      operation: 'insurance_api_call'
    },
    rules: ['no-api-keys', 'no-pii-exposure', 'no-insurance-credentials'],
    context: {
      workflow: 'n8n-claims-processor',
      sensitivity: 'high'
    }
  });

  return check.valid ? toolParams : null;
};

